diff --git a/src/main/java/tools/jackson/databind/type/ClassStack.java b/src/main/java/tools/jackson/databind/type/ClassStack.java
index b5330ba..5b4603f 100644
--- a/src/main/java/tools/jackson/databind/type/ClassStack.java
+++ b/src/main/java/tools/jackson/databind/type/ClassStack.java
@@ -59,6 +59,17 @@ public final class ClassStack
         }
     }

+    /**
+     * Returns true if this stack frame had self-references registered via
+     * {@link #addSelfReference}, meaning the type being built is self-referential
+     * and those references have been (or are about to be) resolved.
+     *
+     * @since 3.x
+     */
+    public boolean hasSelfReferences() {
+        return _selfRefs != null && !_selfRefs.isEmpty();
+    }
+
     public ClassStack find(Class<?> cls)
 diff --git a/src/main/java/tools/jackson/databind/type/TypeFactory.java b/src/main/java/tools/jackson/databind/type/TypeFactory.java
index a6b4b63..8e06582 100644
--- a/src/main/java/tools/jackson/databind/type/TypeFactory.java
+++ b/src/main/java/tools/jackson/databind/type/TypeFactory.java
@@ -1400,10 +1400,28 @@ ClassUtil.nameOf(rawClass), pc, (pc == 1) ? "" : "s", bindings));
             }
         }
         context.resolveSelfReferences(result);
-        // 16-Jul-2016, tatu: [databind#1302] is solved different way, but ideally we shouldn't
-        //     cache anything with partially resolved `ResolvedRecursiveType`... so maybe improve
+        // After resolveSelfReferences() all ResolvedRecursiveType placeholders registered
+        // on this context frame have been patched to reference the fully-built type.
+        // We can now safely cache; the previous concern about partially-resolved types
+        // no longer applies once resolveSelfReferences() returns.
+        // Verify by checking that the context carried self-references: if it did, they
+        // are now resolved, so the result is fully determined and cacheable.
         if (key != null && !result.hasHandlers()) {
             _typeCache.putIfAbsent(key, result); // cache object syncs
+        } else if (key == null && context.hasSelfReferences() && !result.hasHandlers()) {
+            // The cache key was null because type bindings held a ResolvedRecursiveType
+            // placeholder during construction. Now that self-references are resolved we
+            // can build a valid key and cache the fully-resolved type to avoid repeated
+            // expensive resolution on subsequent accesses.
+            Object resolvedKey;
+            if (bindings == null || bindings.isEmpty()) {
+                resolvedKey = rawType;
+            } else {
+                resolvedKey = bindings.asKey(rawType);
+            }
+            if (resolvedKey != null) {
+                _typeCache.putIfAbsent(resolvedKey, result);
+            }
         }
         return result;
     }
